+fn resolved_path_kind(path: &Path) -> (bool, bool) {
+    match fs::symlink_metadata(path) {
+        Ok(meta) if meta.file_type().is_symlink() => match fs::metadata(path) {
+            Ok(meta) => (meta.is_dir(), meta.is_file()),
+            Err(_) => (false, false),
+        },
+        Ok(meta) => (meta.is_dir(), meta.is_file()),
+        Err(_) => (false, false),
